import clsx from 'clsx';
import { Children, type ReactNode } from 'react';
import { useIntl } from 'react-intl';

import { PresetItem } from './PresetItem.js';
import * as styles from './Presets.sty.js';
import { AriaLabelingProps } from '../../../../core/types/a11y-props.js';
import type { BehaviorTrackingProps } from '../../../../core/types/behavior-tracking-props.js';
import { DataTestId } from '../../../../core/types/data-props.js';
import { DOMProps } from '../../../../core/types/dom.js';
import { StylingProps } from '../../../../core/types/styling-props.js';
import { isSlot } from '../../../../core/utils/is-slot.js';
import { devLog } from '../../../../core/utils/logging.js';
import { TIMEFRAME_SELECTOR_PRESETS } from '../../constants/timeframe-presets.js';
import { TIMEFRAME_SELECTOR_MESSAGES } from '../../constants/timeframeSelectorMessages.js';

//#region Typings
/**
 * @public
 */
export interface TimeframeSelectorPresetsProps
  extends DOMProps,
    DataTestId,
    StylingProps,
    BehaviorTrackingProps,
    AriaLabelingProps {
  /** Children shown inside the presets list. A default list of presets is shown if no children are set. */
  children?: ReactNode;
}

//#endregion

/** Iterates over child nodes to extract preset item slots. */
function getItemSlots(children: ReactNode): ReactNode[] | null {
  if (!children) {
    return null;
  }

  const validChildren: ReactNode[] = [];
  for (const child of Children.toArray(children)) {
    if (isSlot(child, PresetItem)) {
      validChildren.push(child);
    } else {
      // do nothing if the child is null (when rendered conditionally for example) and throw a warning otherwise
      devLog(
        'The used child is not supported by the TimeframeSelector.Presets.',
      );
    }
  }

  return validChildren.length > 0 ? validChildren : null;
}

/**
 * A list of preset items shown in the overlay.
 * @public
 */
export const Presets = (props: TimeframeSelectorPresetsProps) => {
  const {
    children,
    'aria-label': ariaLabel,
    className: consumerClassName,
    style: consumerStyle,
    'data-testid': dataTestId,
    ...remainingProps
  }: TimeframeSelectorPresetsProps = props;
  const intl = useIntl();

  const presetsListLabel =
    ariaLabel ??
    intl.formatMessage(TIMEFRAME_SELECTOR_MESSAGES.timeframePresets);

  const validChildren = getItemSlots(children);

  return (
    <ul
      role="listbox"
      aria-label={presetsListLabel}
      className={clsx([styles.listContainer, consumerClassName])}
      style={consumerStyle}
      data-testid={dataTestId}
      {...remainingProps}
    >
      {validChildren ??
        TIMEFRAME_SELECTOR_PRESETS.map((item) => (
          <PresetItem
            key={`${item.from} → ${item.to}`}
            value={item}
            data-dt-name="Preset"
            data-dt-properties={`valueFrom:${item.from},valueTo:${item.to}`}
          />
        ))}
    </ul>
  );
};

Presets['displayName'] = 'TimeframeSelector.Presets';
